import hashlib


def hash_file(filepath, algorithm="sha256", chunk_size=8192):
    """
    Create a cryptographic hash of a file for integrity checking.
    
    Args:
        filepath: Path to the file to hash.
        algorithm: Hash algorithm to use (default: sha256).
                   Supported: sha256, sha384, sha512, sha3_256, sha3_512, blake2b.
        chunk_size: Size of chunks to read at a time (default: 8192 bytes).
    
    Returns:
        Hex digest string of the file hash.
    
    Raises:
        FileNotFoundError: If the file doesn't exist.
        ValueError: If an unsupported algorithm is specified.
    """
    supported_algorithms = {
        "sha256": hashlib.sha256,
        "sha384": hashlib.sha384,
        "sha512": hashlib.sha512,
        "sha3_256": hashlib.sha3_256,
        "sha3_512": hashlib.sha3_512,
        "blake2b": hashlib.blake2b,
    }

    if algorithm not in supported_algorithms:
        raise ValueError(
            f"Unsupported algorithm '{algorithm}'. "
            f"Supported: {', '.join(supported_algorithms.keys())}"
        )

    hasher = supported_algorithms[algorithm]()

    with open(filepath, "rb") as f:
        while True:
            chunk = f.read(chunk_size)
            if not chunk:
                break
            hasher.update(chunk)

    return hasher.hexdigest()


def verify_file(filepath, expected_hash, algorithm="sha256"):
    """
    Verify a file's integrity by comparing its hash to an expected value.
    
    Args:
        filepath: Path to the file to verify.
        expected_hash: The expected hex digest string.
        algorithm: Hash algorithm to use (default: sha256).
    
    Returns:
        True if the file hash matches the expected hash, False otherwise.
    """
    actual_hash = hash_file(filepath, algorithm=algorithm)
    # Use constant-time comparison to prevent timing attacks
    return hashlib.compare_digest(actual_hash.lower(), expected_hash.lower())


